import { Children, type ReactNode } from 'react';
import { isElement } from 'react-is';

import type {
  ChartVariantInternal,
  TimeseriesBand,
  TimeseriesChartAreaProps,
  TimeseriesChartBandProps,
  TimeseriesChartBarProps,
  TimeseriesChartLineProps,
} from './types/timeseries.js';
import type { Timeseries } from '../../core/types/timeseries.js';

export type SeriesSlots = {
  line: Timeseries[];
  area: Timeseries[];
  bar: Timeseries[];
  band: TimeseriesBand[];
  shapePriority: ChartVariantInternal[];
};

const SLOT_DISPLAY_NAMES = {
  line: 'TimeseriesChart.Line',
  area: 'TimeseriesChart.Area',
  bar: 'TimeseriesChart.Bar',
  band: 'TimeseriesChart.Band',
} as const;

type WithDisplayName = { displayName?: string };

export function iterateSeriesSlots(children: ReactNode): SeriesSlots {
  const line: Timeseries[] = [];
  const area: Timeseries[] = [];
  const bar: Timeseries[] = [];
  const band: TimeseriesBand[] = [];
  const shapePriority: ChartVariantInternal[] = [];

  Children.forEach(children, (child) => {
    if (!isElement(child)) {
      return;
    }

    const displayName = (child.type as WithDisplayName).displayName;

    switch (displayName) {
      case SLOT_DISPLAY_NAMES.line: {
        const { data } = child.props as TimeseriesChartLineProps;
        line.push(data);
        if (!shapePriority.includes('line')) {
          shapePriority.push('line');
        }
        break;
      }
      case SLOT_DISPLAY_NAMES.area: {
        const { data } = child.props as TimeseriesChartAreaProps;
        area.push(data);
        if (!shapePriority.includes('area')) {
          shapePriority.push('area');
        }
        break;
      }
      case SLOT_DISPLAY_NAMES.bar: {
        const { data } = child.props as TimeseriesChartBarProps;
        bar.push(data);
        if (!shapePriority.includes('bar')) {
          shapePriority.push('bar');
        }
        break;
      }
      case SLOT_DISPLAY_NAMES.band: {
        const { data } = child.props as TimeseriesChartBandProps;
        band.push(data);
        if (!shapePriority.includes('band')) {
          shapePriority.push('band');
        }
        break;
      }
    }
  });

  return { line, area, bar, band, shapePriority };
}
